const book: BibleBook = {
  id: 'zephaniah',
  name: 'Sofonias',
  englishName: 'Zephaniah',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'Yahweh’s word which came to Zephaniah, the son of Cushi, the son of Gedaliah, the son of Amariah, the son of Hezekiah, in the days of Josiah, the son of Amon, king of Judah.', pt: 'A palavra do Senhor que veio a Sofonias, filho de Cuche, filho de Gedalias, filho de Amarias, filho de Ezequias, nos dias de Josias, filho de Amom, rei de Judá.' },
      { v: 2, en: 'I will utterly sweep away everything from the surface of the earth, says Yahweh.', pt: 'Hei de consumir por completo tudo sobre a face da terra, diz o Senhor.' },
      { v: 3, en: 'I will sweep away man and animal. I will sweep away the birds of the sky, the fish of the sea, and the heaps of rubble with the wicked. I will cut off man from the surface of the earth, says Yahweh.', pt: 'Consumirei os homens e os animais; consumirei as aves do céu, e os peixes do mar, e os tropeços juntamente com os ímpios; e exterminarei os homens de sobre a face da terra, diz o Senhor.' },
      { v: 4, en: 'I will stretch out my hand against Judah, and against all the inhabitants of Jerusalem. I will cut off the remnant of Baal from this place: the name of the idolatrous and pagan priests,', pt: 'E estenderei a minha mão contra Judá, e contra todos os habitantes de Jerusalém; e exterminarei deste lugar o resto de Baal, e os nomes dos sacerdotes de ídolos, juntamente com os sacerdotes;' },
      { v: 5, en: 'those who worship the army of the sky on the housetops, those who worship and swear by Yahweh and also swear by Malcam,', pt: 'e os que sobre os telhados adoram o exército do céu, e aqueles adoradores que juram ao Senhor, e juram por Milcom;' },
      { v: 6, en: 'those who have turned back from following Yahweh, and those who haven’t sought Yahweh nor inquired after him.', pt: 'e os que deixam de seguir ao Senhor, e os que não buscam ao Senhor, nem perguntam por ele.' },
      { v: 7, en: 'Be silent at the presence of the Lord Yahweh, for the day of Yahweh is at hand. For Yahweh has prepared a sacrifice. He has consecrated his guests.', pt: 'Cala-te diante do Senhor Deus, porque o dia do Senhor está perto; pois o Senhor tem preparado um sacrifício, e tem santificado os seus convidados.' },
      { v: 8, en: 'It will happen in the day of Yahweh’s sacrifice, that I will punish the princes, the king’s sons, and all those who are clothed with foreign clothing.', pt: 'E no dia do sacrifício do Senhor castigarei os oficiais, e os filhos do rei, e todos os que se vestem de trajes estrangeiros.' },
      { v: 9, en: 'In that day, I will punish all those who leap over the threshold, who fill their master’s house with violence and deceit.', pt: 'Castigarei também naquele dia todos aqueles que saltam sobre o umbral, que enchem de violência e de dolo a casa do seu senhor.' },
      { v: 10, en: 'In that day, says Yahweh, there will be the noise of a cry from the fish gate, a wailing from the second quarter, and a great crashing from the hills.', pt: 'E naquele dia, diz o Senhor, far-se-á ouvur uma voz de clamor desde a porta dos peixes, e um uivo desde a segunda parte, e grande estrépito desde os outeiros.' },
      { v: 11, en: 'Wail, you inhabitants of Maktesh, for all the people of Canaan are undone! All those who were loaded with silver are cut off.', pt: 'Uivai vós, moradores de Mactes, porque todo o povo de Canaã está arruinado; todos os que pesam a prata são destruídos.' },
      { v: 12, en: 'It will happen at that time, that I will search Jerusalem with lamps, and I will punish the men who are settled on their dregs, who say in their heart, “Yahweh will not do good, neither will he do evil.”', pt: 'E há de ser que, naquele tempo, esquadrinharei a Jerusalém com lanternas, e castigarei os homens que se embrutecem com as fezes do vinho, que dizem no seu coração: O Senhor não faz o bem nem faz o mal.' },
      { v: 13, en: 'Their wealth will become a plunder, and their houses a desolation. Yes, they will build houses, but won’t inhabit them. They will plant vineyards, but won’t drink their wine.', pt: 'Por isso as riquezas deles se tornarão em despojo e as suas casas em desolação; e edificarão casas, mas não habitarão nelas; e plantarão vinhas, mas não lhes beberão o vinho.' },
      { v: 14, en: 'The great day of Yahweh is near. It is near, and hurries greatly, the voice of the day of Yahweh. The mighty man cries there bitterly.', pt: 'O grande dia do Senhor está perto; sim, está perto, e se apressa muito; ei-la, amarga é a voz do dia do Senhor; clama ali o homem poderoso.' },
      { v: 15, en: 'That day is a day of wrath, a day of distress and anguish, a day of trouble and ruin, a day of darkness and gloom, a day of clouds and blackness,', pt: 'Aquele dia é dia de indignação, dia de tribulação e de angústia, dia de alvoroço e de assolação, dia de trevas e de escuridão, dia de nuvens e de densas trevas,' },
      { v: 16, en: 'a day of the trumpet and alarm, against the fortified cities, and against the high battlements.', pt: 'dia de trombeta e de alarido contra as cidades fortificadas e contra as torres altas.' },
      { v: 17, en: 'I will bring distress on men, that they will walk like blind men, because they have sinned against Yahweh, and their blood will be poured out like dust, and their flesh like dung.', pt: 'E angustiarei os homens, e eles andarão como cegos, porque pecaram contra o Senhor; e o seu sangue se derramará como pó, e a sua carne como esterco.' },
      { v: 18, en: 'Neither their silver nor their gold will be able to deliver them in the day of Yahweh’s wrath, but the whole land will be devoured by the fire of his jealousy; for he will make an end, yes, a terrible end, of all those who dwell in the land.', pt: 'Nem a sua prata nem o seu ouro os poderá livrar no dia da indignação do Senhor; mas pelo fogo do seu zelo será devorada toda a terra; porque certamente fará de todos os moradores da terra uma destruição total e apressada.' },
    ],
    2: [
      { v: 1, en: 'Gather yourselves together, yes, gather together, you nation that has no shame,', pt: 'Congregai-vos, sim, congregai-vos, ó nação sem pudor;' },
      { v: 2, en: 'before the appointed time when the day passes as the chaff, before the fierce anger of Yahweh comes on you, before the day of Yahweh’s anger comes on you.', pt: 'antes que o decreto produza efeito, e o dia passe como a pragana; antes que venha sobre vós o furor da ira do Senhor, sim, antes que venha sobre vós o dia da ira do Senhor.' },
      { v: 3, en: 'Seek Yahweh, all you humble of the land, who have kept his ordinances. Seek righteousness. Seek humility. It may be that you will be hidden in the day of Yahweh’s anger.', pt: 'Buscai ao Senhor, vós todos os mansos da terra, que tendes posto por obra o seu juizo; buscai a justiça, buscai a mansidão; porventura sereis escondidos no dia da ira do Senhor.' },
      { v: 4, en: 'For Gaza will be forsaken, and Ashkelon a desolation. They will drive out Ashdod at noonday, and Ekron will be rooted up.', pt: 'Pois Gaza será desamparada, e Asquelom assolada; Asdode ao meio-dia será expelida, e Ecrom desarraigada.' },
      { v: 5, en: 'Woe to the inhabitants of the sea coast, the nation of the Cherethites! Yahweh’s word is against you, Canaan, the land of the Philistines. I will destroy you, that there will be no inhabitant.', pt: 'Ai dos habitantes da borda do mar, da nação dos quereteus! A palavra do Senhor é contra vós, ó Canaã, terra dos filisteus; e eu vos destruirei, sem que fique sequer um habitante.' },
      { v: 6, en: 'The sea coast will be pastures, with cottages for shepherds and folds for flocks.', pt: 'E a borda do mar será de pastagens, com cabanas para os pastores, e currais para os rebanhos.' },
      { v: 7, en: 'The coast will be for the remnant of the house of Judah. They will find pasture. In the houses of Ashkelon, they will lie down in the evening, for Yahweh, their God, will visit them, and restore them.', pt: 'E será a costa para o restante da casa de Judá, para que eles se apascentem ali; de tarde se deitarão nas casas de Asquelom; pois o Senhor seu Deus os visitará, e os fará tornar do seu cativeiro.' },
      { v: 8, en: 'I have heard the reproach of Moab, and the insults of the children of Ammon, with which they have reproached my people, and magnified themselves against their border.', pt: 'Eu ouvi o escárnio de Moabe, e os ultrajes dos filhos de Amom, com que escarneceram do meu povo, e se engrandeceram contra o seu termo.' },
      { v: 9, en: 'Therefore as I live, says Yahweh of Armies, the God of Israel, surely Moab will be as Sodom, and the children of Ammon as Gomorrah, a possession of nettles, and salt pits, and a perpetual desolation. The remnant of my people will plunder them, and the survivors of my nation will inherit them.', pt: 'Portanto diz o Senhor dos exércitos, o Deus de Israel: Tão certo como eu vivo, Moabe será como Sodoma, e os filhos de Amom como Gomorra, campo de urtigas e poços de sal, e desolação perpétua; o restante do meu povo os saqueará, e o restante da minha nação os possuira.' },
      { v: 10, en: 'This they will have for their pride, because they have reproached and magnified themselves against the people of Yahweh of Armies.', pt: 'Isso terão em recompensa da sua soberba, porque usaram de escárnios, e se engrandeceram contra o povo do Senhor dos exércitos.' },
      { v: 11, en: 'Yahweh will be awesome to them, for he will famish all the gods of the land. Men will worship him, everyone from his place, even all the shores of the nations.', pt: 'O Senhor se mostrará terrível contra eles; pois aniquilará todos os deuses da terra, e adorá-lo-ão, cada uma desde o seu lugar, todas as ilhas das nações.' },
      { v: 12, en: 'You Cushites also, you will be killed by my sword.', pt: 'Também vós, ó etíopes, sereis mortos pela minha espada.' },
      { v: 13, en: 'He will stretch out his hand against the north, destroy Assyria, and will make Nineveh a desolation, as dry as the wilderness.', pt: 'Ainda ele estenderá a mão contra o Norte, e destruirá a Assíria; e fará de Nínive uma desolação, terra árida como o deserto.' },
      { v: 14, en: 'Herds will lie down in the middle of her, all the animals of the nations. Both the pelican and the porcupine will lodge in its capitals. Their calls will echo through the windows. Desolation will be in the thresholds, for he has laid bare the cedar beams.', pt: 'E no meio dela se deitarão manadas, todas as feras do campo; e alojar-se-ão nos capitéis dela tanto o pelicano como o ouriço; a voz das aves se ouvirá nas janelas; e haverá desolação nos limiares; pois ele tem posto a descoberto a obra de cedro.' },
      { v: 15, en: 'This is the joyous city that lived carelessly, that said in her heart, “I am, and there is no one besides me.” How she has become a desolation, a place for animals to lie down in! Everyone who passes by her will hiss, and shake their fists.', pt: 'Esta é a cidade alegre, que vivia em segurança, que dizia no seu coração: Eu sou, e fora de mim não há outra. Como se tem ela tornado em desolação, em covil de feras! Todo o que passar por ela assobiará, e meneará a mão' },
    ],
    3: [
      { v: 1, en: 'Woe to her who is rebellious and polluted, the oppressing city!', pt: 'Ai da rebelde e contaminada, da cidade opressora!' },
      { v: 2, en: 'She didn’t obey the voice. She didn’t receive correction. She didn’t trust in Yahweh. She didn’t draw near to her God.', pt: 'Não escuta a voz, não aceita a correção, não confia no Senhor, nem se aproxima do seu Deus.' },
      { v: 3, en: 'Her princes within her are roaring lions. Her judges are evening wolves. They leave nothing until the next day.', pt: 'Os seus oficiais são leões rugidores no meio dela; os seus juízes são lobos da tarde, que nada deixam para o dia seguinte.' },
      { v: 4, en: 'Her prophets are arrogant and treacherous people. Her priests have profaned the sanctuary. They have done violence to the law.', pt: 'Os seus profetas são levianos, homens aleivosos; os seus sacerdotes profanam o santuário, e fazem violência à lei.' },
      { v: 5, en: 'Yahweh, within her, is righteous. He will do no wrong. Every morning he brings his justice to light. He doesn’t fail, but the unjust know no shame.', pt: 'O Senhor é justo no meio dela; ele não comete iniqüidade; cada manhã traz o seu juízo à luz; nunca falta; o injusto, porém, não conhece a vergonha.' },
      { v: 6, en: 'I have cut off nations. Their battlements are desolate. I have made their streets waste, so that no one passes by. Their cities are destroyed, so that there is no man, so that there is no inhabitant.', pt: 'Exterminei as nações, as suas torres estão assoladas; fiz desertas as suas praças a ponto de não ficar quem passe por elas; as suas cidades foram destruídas, até não ficar ninguém, até não haver quem as habite.' },
      { v: 7, en: 'I said, “Just fear me. Receive correction, so that her dwelling won’t be cut off, according to all that I have appointed concerning her.” But they rose early and corrupted all their doings.', pt: 'Eu dizia: Certamente me temerás e aceitarás a correção; e assim a sua morada não seria destruída, conforme tudo o que eu havia determinado a respeito dela. Mas eles se levantaram de madrugada, e corromperam todas as suas obras.' },
      { v: 8, en: '“Therefore wait for me”, says Yahweh, “until the day that I rise up to the prey, for my determination is to gather the nations, that I may assemble the kingdoms, to pour on them my indignation, even all my fierce anger, for all the earth will be devoured with the fire of my jealousy.', pt: 'Portanto esperai-me a mim, diz o Senhor, no dia em que eu me levantar para o despojo; porque o meu intento é ajuntar nações e congregar reinos, para sobre eles derramar a minha indignação, e todo o ardor da minha ira; pois esta terra toda será consumida pelo fogo do meu zelo.' },
      { v: 9, en: 'For then I will purify the lips of the peoples, that they may all call on Yahweh’s name, to serve him shoulder to shoulder.', pt: 'Pois então darei lábios puros aos povos, para que todos invoquem o nome do Senhor, e o sirvam com o mesmo espírito.' },
      { v: 10, en: 'From beyond the rivers of Cush, my worshipers, even the daughter of my dispersed people, will bring my offering.', pt: 'Dalém dos rios da Etiópia os meus adoradores, a saber, a filha dos meus dispersos, trarão a minha oferta.' },
      { v: 11, en: 'In that day you will not be disappointed for all your doings, in which you have transgressed against me; for then I will take away out from among you your proudly exulting ones, and you will no more be haughty in my holy mountain.', pt: 'Naquele dia não te envergonharás de nenhuma das tuas obras, com que te rebelaste contra mim; porque então tirarei do meio de ti, os que exultam arrogantemente, e tu nunca mais te ensoberbeceras no meu santo monte.' },
      { v: 12, en: 'But I will leave among you an afflicted and poor people, and they will take refuge in Yahweh’s name.', pt: 'Mas deixarei no meio de ti um povo humilde e pobre; e eles confiarão no nome do Senhor.' },
      { v: 13, en: 'The remnant of Israel will not do iniquity, nor speak lies, neither will a deceitful tongue be found in their mouth, for they will feed and lie down, and no one will make them afraid.”', pt: 'O remanescente de Israel não cometerá iniqüidade, nem proferirá mentira, e na sua boca não se achará língua enganosa; pois serão apascentados, e se deitarão, e não haverá quem os espante.' },
      { v: 14, en: 'Sing, daughter of Zion! Shout, Israel! Be glad and rejoice with all your heart, daughter of Jerusalem.', pt: 'Canta alegremente, ó filha de Sião; rejubila, ó Israel; regozija-te, e exulta de todo o coração, ó filha de Jerusalém.' },
      { v: 15, en: 'Yahweh has taken away your judgments. He has thrown out your enemy. The King of Israel, Yahweh, is among you. You will not be afraid of evil any more.', pt: 'O Senhor afastou os juízos que havia contra ti, lançou fora o teu inimigo; o Rei de Israel, o Senhor, está no meio de ti; não temerás daqui em diante mal algum.' },
      { v: 16, en: 'In that day, it will be said to Jerusalem, “Don’t be afraid, Zion. Don’t let your hands be weak.”', pt: 'Naquele dia se dirá a Jerusalém: Não temas, ó Sião; não se enfraqueçam as tuas mãos.' },
      { v: 17, en: 'Yahweh, your God, is among you, a mighty one who will save. He will rejoice over you with joy. He will calm you in his love. He will rejoice over you with singing.', pt: 'O Senhor teu Deus está no meio de ti, poderoso para te salvar; ele se deleitará em ti com alegria; renovar-te-á no seu amor, regozijar-se-á em ti com júbilo.' },
      { v: 18, en: 'I will remove those who grieve about the appointed feasts from you. They are a burden and a reproach to you.', pt: 'Os que em tristeza suspiram pela assembléia solene, os quais te pertenciam, eu os congregarei; esses para os quais era um opróbrio o peso que estava sobre ela.' },
      { v: 19, en: 'Behold, at that time I will deal with all those who afflict you, and I will save those who are lame, and gather those who were driven away. I will give them praise and honor, whose shame has been in all the earth.', pt: 'Eis que naquele tempo procederei contra todos os que te afligem; e salvarei a que coxeia, e recolherei a que foi expulsa; e deles farei um louvor e um nome em toda a terra em que têm sido envergonhados.' },
      { v: 20, en: 'At that time will I bring you in, and at that time will I gather you; for I will give you honor and praise among all the peoples of the earth, when I restore your fortunes before your eyes, says Yahweh.', pt: 'Naquele tempo vos trarei, naquele tempo vos recolherei; porque farei de vós um nome e um louvor entre todos os povos da terra, quando eu tornar o vosso cativeiro diante dos vossos olhos, diz o Senhor.' },
    ],
  },
};

export default book;
